import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjSelectMany } from "./OjSelectMany";
export { OjSelectMany };

/**
 * Create an instance of [[OjSelectMany]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojSelectMany(driver, By.id('my-oj-select-many'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojSelectMany(driver: DriverLike, by: By): Promise<OjSelectMany> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjSelectMany
  if (!(webEl instanceof OjSelectMany)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-select-many>`);
  }
  return webEl;
}

register("oj-select-many", OjSelectMany);
